// // This module is designed to read an input temperature value and trigger an alarm if the temperature is below the specified threshold.
module temperature_sensor_controller (
    input wire clk,
    input wire reset,
    input wire [7:0] temperature,
    input wire [7:0] threshold,
    output reg alarm
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        alarm <= 0;
    end else if (temperature > threshold) begin
        alarm <= 1;
    end else begin
        alarm <= 0;
    end
end

endmodule
